import { getStudioState } from "../agentSessionChannel.js";
import { getConfig, hasCredentials } from "../config.js";
import { positionalArgs } from "../parseArgs.js";
const ARGS = [{ name: "sessionId", format: "uuid" }];
const args = positionalArgs(ARGS);
const sessionId = args[0];
if (!hasCredentials()) {
    console.error("Not authenticated.");
    process.exit(1);
}
const config = getConfig();
if (!config.apiKey) {
    console.error("No API key configured.");
    process.exit(1);
}
try {
    const state = await getStudioState({
        serviceUrl: config.serviceUrl,
        apiKey: config.apiKey,
        sessionId,
    });
    process.stdout.write(`${JSON.stringify(state)}\n`);
    process.exit(0);
}
catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    console.error(message);
    process.exit(1);
}
